mapper.select:
select id, log_type, title, service_id, create_by, update_by, create_time, update_time, remote_addr, user_agent, request_uri, method, params, time, del_flag, exception
from sys_log where log_type = '0' and request_uri = '/oauth2/token' and create_by = #{username}
order by create_time desc limit 1
